#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2e5+10;int cnt;
int a[N],n,m;int sm[N<<2];bool vs[N<<2];
inline void update(int cur)
{
	vs[cur]=vs[cur<<1]|vs[cur<<1|1];
	sm[cur]=sm[cur<<1]+sm[cur<<1|1];
}
inline void build(int l=1,int r=n,int cur=1)
{
	if(l==r){vs[cur]=((sm[cur]=a[l])>1);return;}int mid=(l+r)>>1;
	if(l<=mid)build(l,mid,cur<<1);if(r>mid)build(mid+1,r,cur<<1|1);update(cur);
}
inline void Sqr(int ql,int qr,int l=1,int r=n,int cur=1)
{
	if(!vs[cur])return;if(l==r){sm[cur]=a[l]=sqrt(a[l]);vs[cur]=a[l]>1;return;}int mid=(l+r)>>1;
	if(ql<=mid)Sqr(ql,qr,l,mid,cur<<1);if(qr>mid)Sqr(ql,qr,mid+1,r,cur<<1|1);update(cur);return;
}
inline int qry(int ql,int qr,int l=1,int r=n,int cur=1)
{
	if(ql<=l&&r<=qr){return sm[cur];}int mid=(l+r)>>1;int res=0;
	if(ql<=mid)res+=qry(ql,qr,l,mid,cur<<1);if(qr>mid)res+=qry(ql,qr,mid+1,r,cur<<1|1);return res;
}
inline void mian(int N)
{
	printf("Case #%lld:\n",++cnt);
	n=N;rep(1,n,i)a[i]=read();build();
	int T=read();while(T--)
	{
		bool opt=read();int l,r;
		switch(opt)
		{
			case 1: l=read();r=read();if(l>r){int tmp=l;l=r;r=tmp;}printf("%lld\n",qry(l,r));break;
			case 0: l=read();r=read();if(l>r){int tmp=l;l=r;r=tmp;}Sqr(l,r);break;
		}
	}
	return;
}
signed main()
{
	int T;while(scanf("%lld",&T)!=EOF)mian(T);return 0;
}
